#include <bits/stdc++.h>
using namespace std;

const int N=410,mod=1e9+7;

int n,m,c,fac[N],inv[N];

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int C(int n,int m){
    return 1ll*fac[n]*inv[n-m]%mod*inv[m]%mod;
}

int main(){
    fac[0]=1;
    for(int i=1;i<N;i++)
        fac[i]=1ll*fac[i-1]*i%mod;
    inv[N-1]=qpow(fac[N-1],mod-2);
    for(int i=N-2;i>=0;i--)
        inv[i]=1ll*inv[i+1]*(i+1)%mod;
    scanf("%d%d%d",&n,&m,&c);
    int ans=0;
    for(int k=0;k<=c;k++)
        for(int i=0,p=1;i<=n;i++,p=1ll*p*(k+1)%mod)
            for(int j=0,cnt=1;j<=m;j++,cnt=1ll*cnt*p%mod){
                if((n-i+m-j+c-k)%2)
                    ans=(ans-1ll*C(n,i)*C(m,j)%mod*C(c,k)%mod*cnt%mod)%mod;
                else
                    ans=(ans+1ll*C(n,i)*C(m,j)%mod*C(c,k)%mod*cnt%mod)%mod;
            }
    printf("%d",(ans+mod)%mod);
    return 0;
}
